const rawOutput = $json.output || "";

// ১. চেক করা হচ্ছে আউটপুটটি কি JSON নাকি সাধারণ টেক্সট (যেমন: Ben Arfa সম্পর্কে উত্তর)
if (!rawOutput.trim().startsWith('{')) {
    // এটি সাধারণ টেক্সট হলে সরাসরি রিটার্ন করবে
    return [{
        json: {
            isGeneral: true,
            response: rawOutput,
            // পরবর্তী নোডগুলোর এরর এড়াতে খালি ফিল্ড রাখা হয়েছে
            subject: "General",
            topic: "Conversation",
            concept: "General Knowledge",
            difficulty: "N/A",
            question: rawOutput.substring(0, 50) + "..."
        }
    }];
}

// ২. যদি আউটপুটটি JSON হয়, তবে সেটিকে পার্স (Parse) করার চেষ্টা করবে
try {
    const cleanedOutput = rawOutput
        .replace(/```json/g, "")
        .replace(/```/g, "")
        .trim();

    const parsedData = JSON.parse(cleanedOutput);

    return [{
        json: {
            isGeneral: false,
            subject: parsedData.subject || "Unknown",
            topic: parsedData.topic || "Unknown",
            concept: parsedData.concept || "Unknown",
            difficulty: parsedData.difficulty || "Basic",
            question: parsedData.question || "No question provided"
        }
    }];
} catch (error) {
    // যদি JSON ফরমেটে কোনো ভুল থাকে, তবে সেটিকেও টেক্সট হিসেবে পাঠাবে
    return [{
        json: {
            isGeneral: true,
            response: rawOutput,
            error: "JSON Parsing failed, treating as plain text"
        }
    }];
}

const metadata = $json; 
const aiResponse = $json.output || "";

const cleanString = (val) => {
    if (typeof val !== 'string') return val;
    return val.replace(/[\r\n\t]+/gm, " ").replace(/\s\s+/g, ' ').trim();
};

return [{
    json: {

        user_input: cleanString($node["When chat message received"]?.json?.chatInput || ""),
        ai_response: aiResponse.trim(),
        subject: cleanString(metadata.subject || "N/A"),
        topic: cleanString(metadata.topic || "N/A"),
        concept: cleanString(metadata.concept || "N/A"),
        difficulty: cleanString(metadata.difficulty || "N/A")
    }
}];

// This cleans the final output for the user's chat window
const rawResponse = $node["AI Agent1"].json.output || "";
const userInput = $node["When chat message received"].json.chatInput;

// Function to remove all trailing newlines and system prefixes for the display
const cleanDisplay = (text) => {
    if (typeof text !== 'string') return text;
    // Removes trailing newlines and internal prefixing like "topic →"
    return text.replace(/topic\s*→\s*/gi, '')
               .replace(/subject\s*→\s*/gi, '')
               .replace(/[\r\n]+$/, '') 
               .trim();
};

return [{
    json: {
        output: cleanDisplay(rawResponse),
        original_query: cleanDisplay(userInput)
    }
}];

// FINAL MASTER FORMATTER: The "Human-Readable" UI Layer
const rawResponse = $node["AI Agent1"].json.output || "";

const makeMathBeautiful = (text) => {
    if (typeof text !== 'string') return text;

    return text
        // 1. Remove n8n Metadata Labels
        .replace(/(subject|topic|concept|difficulty)\s*→\s*/gi, '')

        // 2. Fix Fractions: \frac{a}{b} -> (a / b)
        .replace(/\\frac\{([^}]*)\}\{([^}]*)\}/g, '($1 / $2)')

        // 3. Fix Bold Vectors: \mathbf{w} -> w
        .replace(/\\mathbf\{([^}]*)\}/g, '$1')

        // 4. Fix Partial Derivatives: \partial -> ∂
        .replace(/\\partial/g, '∂')

        // 5. Fix Summations and Sigmas: \sum -> Σ, \sigma -> σ
        .replace(/\\sum/g, 'Σ').replace(/\\sigma/g, 'σ')

        // 6. Fix Superscripts & Subscripts (e.g., x^(i), e^-z, b_0)
        .replace(/\^\{?([-+0-9a-z]*)\}?/g, '^$1') 
        .replace(/_\{?([0-9a-z]*)\}?/g, '_$1')

        // 7. Clean up Greek Letters
        .replace(/\\alpha/g, 'α').replace(/\\log/g, 'log')

        // 8. Strip LaTeX structural brackets \[ \] \( \)
        .replace(/\\\[|\\\]|\\\(|\\\)/g, '')
        .replace(/\\left\[|\\right\]|\\left\(|\\right\)/g, '')

        // 9. Remove lingering curly braces
        .replace(/[\{\}]/g, '')

        // 10. Final Newline Cleanup
        .replace(/[\r\n]+$/, '') 
        .trim();
};

return [{
    json: {
        output: makeMathBeautiful(rawResponse)
    }
}];
